const a="http://localhost:5000/api";async function t(s,e={}){const n=await fetch(`${a}${s}`,{headers:{"Content-Type":"application/json",...e.headers||{}},...e}),o=await n.json().catch(()=>({}));if(!n.ok)throw new Error(o?.message||"Request failed");return o}async function r(){return t("/session/start",{method:"POST"})}async function c(s){return t("/session/end",{method:"POST",body:JSON.stringify({sessionId:s})})}async function i(s){return t("/focus/save",{method:"POST",body:JSON.stringify(s)})}async function u(s){return t(`/report/${s}`,{method:"GET"})}export{r as a,c as e,u as f,i as s};
